import triton
import triton.language as tl
import torch

@triton.jit
def sigmoid(x):
    return 1 / (1 + tl.exp(-x))

@triton.jit
def silu(x):
    return x * sigmoid(x)

@triton.jit
def tanh(x):
    return (tl.exp(x) - tl.exp(-x)) / (tl.exp(x) + tl.exp(-x))

@triton.jit
def f_kernel(x_ptr, y_ptr, n_elements, BLOCK_SIZE: tl.constexpr):
