import triton.language as tl
import torch

@triton.jit
def f_kernel(x_ptr, output_ptr, n, m, k, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(axis=0)
    block_start = pid * BLOCK_SIZE
    block_end = min(block_start + BLOCK_SIZE, n)
    for i in range(block_start, block_end):
        max_val = -float('inf')
        max_idx = 0
        for j in range(m):
            for k in range(k):
                val = tl.sigmoid(tl.load(x_ptr + i * m * k + j * k + k))
                if val > max_val:
                    max_val = val
                    max_idx = j
        tl.store(output_ptr + i * m + max_idx, 1.0)

def f(x):
    n, m, k = x.shape
    output = torch.zeros((n, m, 1), dtype=torch.float32, device=x.device)
    BLOCK_SIZE = 1024
    grid = lambda meta: (triton.cdiv(n, meta['BLOCK_SIZE']),)
    f_kernel[grid](x.contiguous(), output.contiguous(), n, m, k, BLOCK_SIZE=BLOCK_SIZE)
    return output.argmax(dim=-1, keepdim=True)

import triton
import triton.language as tl
import torch

@triton.jit
def fused_attention_kernel(
    arg0_ptr, arg1_ptr, arg2_ptr, out_ptr,
    M: tl.constexpr, N: tl.constexpr, K: tl.constexpr,
    BLOCK_M: tl.constexpr, BLOCK_N: tl.constexpr, BLOCK_K: tl.constexpr,
    scale: tl.constexpr
):
    pid = tl.program_id(axis=0)
    bid_m = pid // (N // BLOCK_N)
    bid_n = pid % (N // BLOCK_N)
    bid_k = tl.program_id(axis=1)

    # Load data
    arg0 = tl.zeros([BLOCK_M, BLOCK_K], dtype=tl.float32)
    arg1 = tl.zeros([BLOCK_K, BLOCK_N], dtype=tl.float32)
    arg2 = tl.zeros([BLOCK_N, BLOCK_K], dtype=tl.float32)
    for i in range(0, BLOCK_M):
        for j in range(0, BLOCK_K):
            arg0[i, j] = tl.load(arg0_ptr + (bid_m * BLOCK_M + i) * K + (bid_k * BLOCK_K + j), mask=(i < M) & (j < K), other=0.0)
    for i in range(0, BLOCK_K):
        for j in range(0, BLOCK_N):
            arg1[i, j] = tl.load(arg1_ptr + (bid_k * BLOCK_K + i) * N + (bid_n * BLOCK_N + j), mask=(i < K) & (j < N), other=0.0)
    for i in range(0, BLOCK_N):
        for j in range(0, BLOCK_K):
            arg2[i, j] = tl.load(arg2_ptr + (bid_n * BLOCK_N + i) * K + (bid_k * BLOCK_K + j), mask=(i < N) & (j < K), other=0.0)

    # Matmul
    scores = tl.zeros([BLOCK_M, BLOCK_N], dtype=tl.float32)
    for i in range(0, BLOCK_M):
        for j in range(0, BLOCK_N):
            for k in range(0, BLOCK_K):
                scores[i, j] += arg0[i, k] * arg1[k, j]

    # Scale
    scaled = scores * scale

    # Softmax
    max_val = tl.max(scaled, axis=1, keepdim=True)
    exp_scaled = tl.exp(scaled - max_val)
    sum_exp = tl.sum(exp_scaled, axis=1, keepdim=True)
    weights = exp_scaled / sum_exp

    # Matmul
    out = tl.zeros([BLOCK_M, BLOCK_K], dtype=tl.float32)
    for i in range(0, BLOCK_M):
        for j in range(0, BLOCK_K):
            for k in range(0, BLOCK_N):
                out[i, j] += weights[i, k] * arg2[k, j]

    # Store data
    for i in range(0, BLOCK_M):
        for j in range(0, BLOCK_K):
            tl.store(out_ptr + (bid_m * BLOCK_M + i) * K + (bid_k * BLOCK_K + j), out[i, j], mask=(i < M) & (j < K))

def fused_attention(arg0, arg1, arg2):
    M, N, K = arg0.shape[2], arg1.shape[2], arg0.shape[3]
    BLOCK_M, BLOCK_N, BLOCK_K = 64, 64, 32
    scale = 0.125

    out = torch.empty_like(arg0)
    grid = lambda META: (triton.cdiv(M, META['BLOCK_M']) * triton.cdiv(N, META['BLOCK_N']), triton.cdiv(K, META['BLOCK_K']))
    fused_attention_kernel[grid](arg0.contiguous(), arg1.contiguous(), arg2.contiguous(), out, M, N, K, BLOCK_M, BLOCK_N, BLOCK_K, scale)
    return out

import triton
import triton.language as tl
import torch

@triton.jit
def fused_kernel(x_ptr, y_ptr, n, m, k, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(axis=0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n * m

    x = tl.load(x_ptr + offsets, mask=mask, other=0.0)
    y = 0.5 * x * (1.0 + tl.tanh(0.7978845608028654 * x * (1.0 + 0.044715 * x * x)))
    tl.store(y_ptr + offsets, y, mask=mask)

    # Reduction
    sum_val = tl.zeros([BLOCK_SIZE], dtype=tl.float16)
    for i in range(0, BLOCK_SIZE, 32):
        sum_val[i:i+32] = tl.sum(y[i:i+32], axis=0)
    for i in range(0, 32, 16):
        sum_val[i:i+16] = tl.sum(sum_val[i:i+16], axis=0)
    for i in range(0, 16, 8):
        sum_val[i:i+8] = tl.sum(sum_val[i:i+8], axis=0)
    for i in range(0, 8, 4):
        sum_val[i:i+4] = tl.sum(sum_val[i:i+4], axis=0)
    for i in range(0, 4, 2):
        sum_val[i:i+2] = tl.sum(sum_val[i:i+2], axis=0)
    for i in range(0, 2, 1):
        sum_val[i:i+1] = tl.sum(sum_val[i:i+1], axis=0)

    if pid == 0:
        tl.store(y_ptr, sum_val[0], mask=tl.arange(0, 1) < 1)

def fused(x):
    n, m, k = x.shape
    y = torch.empty((n, k), dtype=torch.float16, device=x.device)
    grid = lambda meta: (triton.cdiv(n * m, meta['BLOCK_SIZE']),)
    fused_kernel[grid](x, y, n, m, k, BLOCK_SIZE=1024)
    return y.view(n, k)
